      {
        "term": "Confirmed Order",
        "definition": "An order that has been paid and is queued for fulfillment. It is immutable — no further changes are permitted. This is the established, in-use definition."
      },
      {
        "term": "Confirmed Quote (proposed)",
        "definition": "A quote where the customer has verbally agreed to terms but payment has NOT occurred. The quote is still mutable (payment terms could change, customer could withdraw). This directly contradicts the existing semantics of 'confirmed'."
      }
    ]
  },

