  "rejection_reasons": [
    {
      "violation": "Ubiquitous language collision: 'confirmed' is reused across bounded contexts with contradictory semantics (paid/immutable vs. unpaid/mutable)",
      "business_rule_broken": "A confirmed order is paid and immutable. A 'confirmed quote' as proposed is unpaid and mutable. Using the same term for opposite states violates domain integrity."
    }
  ]
